- **CLI Commands**:
  - `npm install sequelize-cli --save-dev`
  - `npx sequelize-cli init`
  - `npx sequelize-cli model:create --name User --attributes username:string,email:string,password:string`

- **Latest Versions**:
  - Sequelize: 6.30.2
  - Sequelize-typescript: 1.2.1

- **Key Config Options**:
  - `config/config.json`: Define database connection details.
    ```json
    {
      "development": {
        "username": "user",
        "password": "password",
        "database": "database_name",
        "host": "localhost",
        "dialect": "postgres"
      }
    }
    ```
  - `models/User.ts`: Define Sequelize model.
    ```typescript
    import { Model, DataTypes } from 'sequelize-typescript';

    export class User extends Model<User> {
      public id!: number;
      public username!: string;
      public email!: string;
      public password!: string;

      static initModel(sequelize: any) {
        User.init({
          id: {
            type: DataTypes.INTEGER,
            primaryKey: true,
            autoIncrement: true
          },
          username: {
            type: DataTypes.STRING,
            allowNull: false
          },
          email: {
            type: DataTypes.STRING,
            allowNull: false
          },
          password: {
            type: DataTypes.STRING,
            allowNull: false
          }
        }, { sequelize, modelName: 'user' });
      }
    }
    ```
  - `migrations`: Define database migrations.
    ```typescript
    import { QueryInterface, Sequelize } from 'sequelize-typescript';

    export default {
      up: async (queryInterface: QueryInterface, Sequelize: Sequelize) => {
        await queryInterface.createTable('users', {
          id: {
            type: Sequelize.INTEGER,
            primaryKey: true,
            autoIncrement: true
          },
          username: {
            type: Sequelize.STRING,
            allowNull: false
          },
          email: {
            type: Sequelize.STRING,
            allowNull: false
          },
          password: {
            type: Sequelize.STRING,
            allowNull: false
          }
        });
      },

      down: async (queryInterface: QueryInterface) => {
        await queryInterface.dropTable('users');
      }
    };
    ```

- **CRUD Operations**:
  - Create:
    ```typescript
    const user = await User.create({ username: 'john', email: 'john@example.com', password: 'password' });
    ```
  - Read:
    ```typescript
    const users = await User.findAll();
    ```
  - Update:
    ```typescript
    const user = await User.findByPk(1);
    if (user) {
      user.username = 'jane';
      await user.save();
    }
    ```
  - Delete:
    ```typescript
    const user = await User.findByPk(1);
    if (user) {
      await user.destroy();
    }
    ```

